```typescript
type DeepReadonly<T> = 
  T extends (infer U)[] 
    ? readonly DeepReadonly<U>[] 
    : T extends Record<string, any> 
      ? { readonly [K in keyof T]: DeepReadonly<T[K]> } 
      : T;

// Usage example:
interface User {
  name: string;
  address: {
    city: string;
    zip: number;
  };
  hobbies: string[];
}

type ReadonlyUser = DeepReadonly<User>;
// ReadonlyUser is:
// {
//   readonly name: string;
//   readonly address: {
//     readonly city: string;
//     readonly zip: number;
//   };
//   readonly hobbies: readonly string[];
// }
```

```typescript
type DeepReadonly = T extends (...args: any[]) => any
  ? T
  : T extends object
  ? { readonly [P in keyof T]: DeepReadonly }
  : T;

// Usage Example

interface User {
  id: number;
  name: string;
  preferences: {
    theme: string;
    notifications: boolean;
  };
  roles: string[];
}

const user: DeepReadonly<User> = {
  id: 1,
  name: "Alice",
  preferences: {
    theme: "dark",
    notifications: true,
  },
  roles: ["admin", "editor"],
};

// Valid: reading properties
console.log(user.name);
console.log(user.preferences.theme);

// Error: Cannot assign to 'name' because it is a read-only property
// user.name = "Bob";

// Error: Cannot assign to 'theme' because it is a read-only property
// user.preferences.theme = "light";

// Error: Property 'push' does not exist on type 'readonly string[]'
// user.roles.push("guest");
```

```typescript
type DeepReadonly<T> = T extends readonly (infer U)[]
  ? ReadonlyArray<DeepReadonly<U>>
  : T extends Function
    ? T
    : T extends object
      ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
      : T;

// Usage example
interface User {
  name: string;
  address: {
    street: string;
    city: string;
  };
  hobbies: string[];
}

type ReadonlyUser = DeepReadonly<User>;

const user: ReadonlyUser = {
  name: "Alice",
  address: { street: "123 Main", city: "NYC" },
  hobbies: ["reading", "coding"]
};

// user.name = "Bob"; // Error
// user.address.street = "456"; // Error
// user.hobbies.push("swimming"); // Error
```

```typescript
type DeepReadonly<T> = 
  T extends Function 
    ? T 
    : T extends readonly (infer U)[] 
      ? ReadonlyArray<DeepReadonly<U>>
      : T extends object 
        ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
        : T;

// Usage example
interface User {
  name: string;
  settings: {
    theme: string;
    notifications: boolean[];
  };
  tags: string[];
}

const user: DeepReadonly<User> = {
  name: "Alice",
  settings: {
    theme: "dark",
    notifications: [true, false]
  },
  tags: ["admin"]
};

// user.name = "Bob"; // Error: Cannot assign to 'name' because it is a read-only property.
// user.settings.theme = "light"; // Error: Cannot assign to 'theme' because it is a read-only property.
// user.tags.push("user"); // Error: Property 'push' does not exist on type 'readonly string[]'.
```

```typescript
type DeepReadonly<T> = T extends (infer U)[]
  ? ReadonlyArray<DeepReadonly<U>>
  : T extends object
  ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;

// Usage example
interface Config {
  server: {
    port: number;
    hosts: string[];
  };
  debug: boolean;
}

const config: DeepReadonly<Config> = {
  server: {
    port: 3000,
    hosts: ["localhost"]
  },
  debug: true
};

// All of these would be compile-time errors:
// config.debug = false;
// config.server.port = 8080;
// config.server.hosts.push("example.com");
```

type DeepReadonly<T> = {
  readonly [K in keyof T]: T[K] extends object
    ? T[K] extends Function
      ? T[K]
      : DeepReadonly<T[K]>
    : T[K];
};

// Usage example:
interface User {
  name: string;
  address: {
    street: string;
    city: string;
  };
  tags: string[];
}

const user: DeepReadonly<User> = {
  name: "Alice",
  address: {
    street: "123 Main St",
    city: "Wonderland"
  },
  tags: ["developer", "typescript"]
};

// user.name = "Bob"; // Error: cannot assign to 'name' because it is a read-only property
// user.address.city = "Nowhere"; // Error: cannot assign to 'city' because it is a read-only property
// user.tags.push("new"); // Error: Property 'push' does not exist on type 'readonly string[]'

